      reg_in_v  := reg_in_v + 1;
      wait until vld_obs = '1';
      assert unsigned(dat_obs) = to_unsigned(i, length_g)
      report "###ERROR###: Exp value is : " & to_string(i) & "received is: " & to_string(dat_obs)
      severity error;
    end loop;
   ------------------------------------------------------------
    tb_run_s <= false;
    wait;
  end process;

end architecture;
